// src/components/Navbar.jsx
import { Link, useNavigate } from "react-router-dom";
import { useSelector, useDispatch } from "react-redux";
import { clearFormData } from "../redux/form/formSlice"; // Ajusta la ruta según tu estructura
import ModalInfo from "./ModalInfo"; // Asegúrate de que la ruta es correcta
import { useState } from "react";
import "../App.css"; // Asegúrate de que tus estilos están correctamente importados

const Navbar = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate(); // Para redirigir después de logout
  const formData = useSelector((state) => state.form.formData);
  const isLoggedIn = formData.username && formData.email;

  const [showLogoutModal, setShowLogoutModal] = useState(false);

  const handleLogout = () => {
    dispatch(clearFormData());
    setShowLogoutModal(false);
    navigate("/"); // Redirige al Home después de logout
  };

  const handleShowLogoutModal = () => setShowLogoutModal(true);
  const hideLogoutModal = () => setShowLogoutModal(false);

  return (
    <nav className="navbar flex justify-between items-center p-4 bg-gray-100">
      <ul className="navbar-links flex space-x-4">
        <li><Link to="/" className="text-gray-700 hover:text-gray-900">Home</Link></li>
        <li><Link to="/login" className="text-gray-700 hover:text-gray-900">Login</Link></li>
        <li><Link to="/counter" className="text-gray-700 hover:text-gray-900">Counter</Link></li>
        <li><Link to="/think" className="text-gray-700 hover:text-gray-900">Think</Link></li>
        <li><Link to="/products" className="text-gray-700 hover:text-gray-900">Products</Link></li>
        <li><Link to="/about" className="text-gray-700 hover:text-gray-900">About</Link></li>
      </ul>
      <div className="navbar-user-info">
        {isLoggedIn ? (
          <div className="flex items-center space-x-4">
            <span className="text-gray-700">
              Bienvenido <strong className="font-semibold">{formData.username}</strong> | {formData.email}
            </span>
            <button
              onClick={handleShowLogoutModal}
              className="px-3 py-1 bg-blue-600 text-white rounded-md hover:bg-blue-700 transition-colors duration-200"
            >
              Logout
            </button>
            {showLogoutModal && (
              <ModalInfo
                visible={showLogoutModal}
                message="¿Deseas cerrar sesión?"
                onClose={hideLogoutModal}
                isWelcome={false} // Indica que no es un mensaje de bienvenida
              >
                <div className="flex justify-end space-x-2 mt-4">
                  <button
                    onClick={hideLogoutModal}
                    className="px-4 py-2 bg-gray-300 text-gray-700 rounded-md hover:bg-gray-400 transition-colors duration-200"
                  >
                    Cancelar
                  </button>
                  <button
                    onClick={handleLogout}
                    className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 transition-colors duration-200"
                  >
                    Confirmar
                  </button>
                </div>
              </ModalInfo>
            )}
          </div>
        ) : (
          <span className="text-gray-700">Usuario no autenticado</span>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
